import{_ as s}from"./plugin-vue_export-helper-DlAUqK2U.js";import{e as a,f as p,o as e}from"./app-_JojGnWZ.js";const t={};function o(c,n){return e(),a("div",null,n[0]||(n[0]=[p(`<h1 id="python-3-8-新特性与标准库笔记" tabindex="-1"><a class="header-anchor" href="#python-3-8-新特性与标准库笔记"><span>Python 3.8 新特性与标准库笔记</span></a></h1><p>记 Python 3.8 引入的几个语法,顺带把常用标准库(collections、operator、itertools)和闭包、装饰器、property 这些日常会写到的东西一起整理。</p><h2 id="海象表达式" tabindex="-1"><a class="header-anchor" href="#海象表达式"><span>海象表达式 <code>:=</code></span></a></h2><p>可以在表达式内部赋值,省掉一次单独的赋值语句:</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code><span class="line"><span class="token keyword">if</span> <span class="token punctuation">(</span>a <span class="token operator">:=</span> <span class="token number">3</span><span class="token punctuation">)</span> <span class="token operator">&gt;</span> <span class="token number">2</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">print</span><span class="token punctuation">(</span>a<span class="token punctuation">)</span>  <span class="token comment"># 3</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">while</span> <span class="token punctuation">(</span>a <span class="token operator">:=</span> a <span class="token operator">+</span> <span class="token number">1</span><span class="token punctuation">)</span> <span class="token operator">&lt;</span> <span class="token number">10</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">print</span><span class="token punctuation">(</span>a<span class="token punctuation">)</span>  <span class="token comment"># 4, 5, 6, 7, 8, 9</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在列表推导里尤其方便,把中间结果存下来重用:</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code><span class="line">a <span class="token operator">=</span> <span class="token punctuation">[</span>j <span class="token keyword">for</span> j <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">)</span> <span class="token keyword">if</span> <span class="token punctuation">(</span>j <span class="token operator">%</span> <span class="token number">2</span><span class="token punctuation">)</span> <span class="token operator">==</span> <span class="token number">1</span><span class="token punctuation">]</span>      <span class="token comment"># [1, 3, 5, 7, 9]</span></span>
<span class="line">c <span class="token operator">=</span> <span class="token punctuation">[</span>i <span class="token keyword">for</span> j <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">)</span> <span class="token keyword">if</span> <span class="token punctuation">(</span>i <span class="token operator">:=</span> j <span class="token operator">%</span> <span class="token number">2</span><span class="token punctuation">)</span> <span class="token operator">==</span> <span class="token number">1</span><span class="token punctuation">]</span>  <span class="token comment"># [1, 1, 1, 1, 1]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="仅位置参数" tabindex="-1"><a class="header-anchor" href="#仅位置参数"><span>仅位置参数 <code>/</code></span></a></h2><p><code>/</code> 之前的参数只能按位置传,不能写成关键字参数:</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code><span class="line"><span class="token keyword">def</span> <span class="token function">test</span><span class="token punctuation">(</span>a<span class="token punctuation">,</span> b<span class="token punctuation">,</span> c<span class="token punctuation">,</span> <span class="token operator">/</span><span class="token punctuation">,</span> d<span class="token punctuation">,</span> e<span class="token punctuation">,</span> <span class="token operator">**</span>kwargs<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">print</span><span class="token punctuation">(</span>a<span class="token punctuation">,</span> b<span class="token punctuation">,</span> c<span class="token punctuation">,</span> d<span class="token punctuation">,</span> e<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">test<span class="token punctuation">(</span><span class="token string">&#39;a&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;b&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;c&#39;</span><span class="token punctuation">,</span> d<span class="token operator">=</span><span class="token string">&#39;d&#39;</span><span class="token punctuation">,</span> e<span class="token operator">=</span><span class="token string">&#39;e&#39;</span><span class="token punctuation">)</span>   <span class="token comment"># a b c d e</span></span>
<span class="line">test<span class="token punctuation">(</span><span class="token string">&#39;a&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;b&#39;</span><span class="token punctuation">,</span> c<span class="token operator">=</span><span class="token string">&#39;c&#39;</span><span class="token punctuation">,</span> d<span class="token operator">=</span><span class="token string">&#39;d&#39;</span><span class="token punctuation">,</span> e<span class="token operator">=</span><span class="token string">&#39;e&#39;</span><span class="token punctuation">)</span>  <span class="token comment"># TypeError: missing positional argument &#39;c&#39;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="f-string-的-说明符" tabindex="-1"><a class="header-anchor" href="#f-string-的-说明符"><span>f-string 的 <code>=</code> 说明符</span></a></h2><p><code>f&#39;{expr=}&#39;</code> 会展开成&quot;表达式文本 + 等号 + 结果&quot;,调试打印变量名和值时很省事:</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code><span class="line">a<span class="token punctuation">,</span> b <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span></span>
<span class="line"><span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string-interpolation"><span class="token string">f&#39;</span><span class="token interpolation"><span class="token punctuation">{</span>a<span class="token operator">=</span><span class="token punctuation">}</span></span><span class="token string"> </span><span class="token interpolation"><span class="token punctuation">{</span>b<span class="token operator">=</span><span class="token punctuation">}</span></span><span class="token string">&#39;</span></span><span class="token punctuation">)</span>   <span class="token comment"># a=1 b=2</span></span>
<span class="line"><span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string-interpolation"><span class="token string">f&quot;</span><span class="token interpolation"><span class="token punctuation">{</span>a <span class="token operator">=</span> <span class="token punctuation">}</span></span><span class="token string"> </span><span class="token interpolation"><span class="token punctuation">{</span>b <span class="token operator">=</span> <span class="token punctuation">}</span></span><span class="token string">&quot;</span></span><span class="token punctuation">)</span>  <span class="token comment"># a = 1 b = 2(等号两侧加空格会保留)</span></span>
<span class="line"><span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string-interpolation"><span class="token string">f&quot;</span><span class="token interpolation"><span class="token punctuation">{</span>a<span class="token operator">+</span>b<span class="token operator">=</span><span class="token punctuation">}</span></span><span class="token string">&quot;</span></span><span class="token punctuation">)</span>      <span class="token comment"># a+b=3</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>{}</code> 本身要输出就双写:</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code><span class="line">a <span class="token operator">=</span> <span class="token number">0</span></span>
<span class="line"><span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string-interpolation"><span class="token string">f&quot;{{</span><span class="token interpolation"><span class="token punctuation">{</span>a<span class="token punctuation">}</span></span><span class="token string">}}&quot;</span></span><span class="token punctuation">)</span>  <span class="token comment"># {0}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="pip-从-git-装包" tabindex="-1"><a class="header-anchor" href="#pip-从-git-装包"><span>pip 从 git 装包</span></a></h2><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">pip install git+&lt;git仓库地址&gt;</span>
<span class="line">pip install git+&lt;git仓库地址&gt;@&lt;分支名称&gt;</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="字符串" tabindex="-1"><a class="header-anchor" href="#字符串"><span>字符串</span></a></h2><p><code>startswith</code> / <code>endswith</code> 接受元组,可以一次判断多个前缀/后缀。传 list 或 set 不行,得先 <code>tuple()</code> 转一下:</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code><span class="line"><span class="token keyword">if</span> name<span class="token punctuation">.</span>startswith<span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token string">&#39;http:&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;https:&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;ftp:&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p><code>str.format</code> 用 <code>{name}</code> 这种命名占位:</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code><span class="line">s <span class="token operator">=</span> <span class="token string">&#39;{name} hahaha {test}&#39;</span></span>
<span class="line"><span class="token keyword">print</span><span class="token punctuation">(</span>s<span class="token punctuation">.</span><span class="token builtin">format</span><span class="token punctuation">(</span>name<span class="token operator">=</span><span class="token string">&#39;kill&#39;</span><span class="token punctuation">,</span> test<span class="token operator">=</span><span class="token string">&#39;oooooooo&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="高阶函数" tabindex="-1"><a class="header-anchor" href="#高阶函数"><span>高阶函数</span></a></h2><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code><span class="line"><span class="token comment"># map: 对每个元素调用 fun,返回新序列</span></span>
<span class="line"><span class="token builtin">list</span><span class="token punctuation">(</span><span class="token builtin">map</span><span class="token punctuation">(</span><span class="token keyword">lambda</span> a<span class="token punctuation">:</span> a <span class="token operator">+</span> <span class="token number">1</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># [2, 3, 4]</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># reduce: 两两累计</span></span>
<span class="line"><span class="token keyword">from</span> functools <span class="token keyword">import</span> <span class="token builtin">reduce</span></span>
<span class="line"><span class="token builtin">reduce</span><span class="token punctuation">(</span><span class="token keyword">lambda</span> a<span class="token punctuation">,</span> b<span class="token punctuation">:</span> a <span class="token operator">+</span> b<span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span><span class="token punctuation">)</span>  <span class="token comment"># 6</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># filter: 按条件筛选</span></span>
<span class="line"><span class="token builtin">list</span><span class="token punctuation">(</span><span class="token builtin">filter</span><span class="token punctuation">(</span><span class="token keyword">lambda</span> a<span class="token punctuation">:</span> a <span class="token operator">%</span> <span class="token number">2</span> <span class="token operator">==</span> <span class="token number">1</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># [1, 3]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="字典的集合运算" tabindex="-1"><a class="header-anchor" href="#字典的集合运算"><span>字典的集合运算</span></a></h2><p>字典的 <code>keys()</code> 返回的视图支持集合的并、交、差。值集合可能重复,要做集合运算得先转 <code>set</code>:</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code><span class="line">a <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token string">&#39;key&#39;</span><span class="token punctuation">:</span> <span class="token number">1</span><span class="token punctuation">,</span> <span class="token string">&#39;value&#39;</span><span class="token punctuation">:</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token string">&#39;z&#39;</span><span class="token punctuation">:</span> <span class="token number">1</span><span class="token punctuation">,</span> <span class="token string">&#39;w&#39;</span><span class="token punctuation">:</span> <span class="token number">1</span><span class="token punctuation">}</span></span>
<span class="line">b <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token string">&#39;key&#39;</span><span class="token punctuation">:</span> <span class="token number">1</span><span class="token punctuation">,</span> <span class="token string">&#39;value&#39;</span><span class="token punctuation">:</span> <span class="token number">3</span><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">a<span class="token punctuation">.</span>keys<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">&amp;</span> b<span class="token punctuation">.</span>keys<span class="token punctuation">(</span><span class="token punctuation">)</span>    <span class="token comment"># {&#39;value&#39;, &#39;key&#39;}  键的交集</span></span>
<span class="line">a<span class="token punctuation">.</span>items<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">&amp;</span> b<span class="token punctuation">.</span>items<span class="token punctuation">(</span><span class="token punctuation">)</span>  <span class="token comment"># {(&#39;key&#39;, 1)}      键值对交集</span></span>
<span class="line">a<span class="token punctuation">.</span>keys<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">-</span> b<span class="token punctuation">.</span>keys<span class="token punctuation">(</span><span class="token punctuation">)</span>    <span class="token comment"># {&#39;z&#39;, &#39;w&#39;}        键的差集</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 用差集挑出想保留的键</span></span>
<span class="line">c <span class="token operator">=</span> <span class="token punctuation">{</span>k<span class="token punctuation">:</span> a<span class="token punctuation">[</span>k<span class="token punctuation">]</span> <span class="token keyword">for</span> k <span class="token keyword">in</span> a<span class="token punctuation">.</span>keys<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">-</span> <span class="token punctuation">{</span><span class="token string">&#39;z&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;w&#39;</span><span class="token punctuation">}</span><span class="token punctuation">}</span>  <span class="token comment"># {&#39;key&#39;: 1, &#39;value&#39;: 2}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="生成器" tabindex="-1"><a class="header-anchor" href="#生成器"><span>生成器</span></a></h2><p>列表推导一次性把所有元素算出来占内存,把 <code>[]</code> 换成 <code>()</code> 就是生成器,惰性求值省空间:</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code><span class="line">L <span class="token operator">=</span> <span class="token punctuation">[</span>x <span class="token operator">*</span> x <span class="token keyword">for</span> x <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">]</span>  <span class="token comment"># 立刻得到完整 list</span></span>
<span class="line">g <span class="token operator">=</span> <span class="token punctuation">(</span>x <span class="token operator">*</span> x <span class="token keyword">for</span> x <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># generator,边迭代边算</span></span>
<span class="line"><span class="token keyword">for</span> i <span class="token keyword">in</span> g<span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">print</span><span class="token punctuation">(</span>i<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="装饰器" tabindex="-1"><a class="header-anchor" href="#装饰器"><span>装饰器</span></a></h2><p>不改原函数,在调用前后塞功能:</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code><span class="line"><span class="token keyword">def</span> <span class="token function">trace</span><span class="token punctuation">(</span>func<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">def</span> <span class="token function">wrapper</span><span class="token punctuation">(</span><span class="token operator">*</span>args<span class="token punctuation">,</span> <span class="token operator">**</span>kwargs<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">        result <span class="token operator">=</span> func<span class="token punctuation">(</span><span class="token operator">*</span>args<span class="token punctuation">,</span> <span class="token operator">**</span>kwargs<span class="token punctuation">)</span></span>
<span class="line">        <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string-interpolation"><span class="token string">f&#39;</span><span class="token interpolation"><span class="token punctuation">{</span>func<span class="token punctuation">.</span>__name__<span class="token punctuation">}</span></span><span class="token string">(</span><span class="token interpolation"><span class="token punctuation">{</span>args<span class="token conversion-option punctuation">!r</span><span class="token punctuation">}</span></span><span class="token string">, </span><span class="token interpolation"><span class="token punctuation">{</span>kwargs<span class="token conversion-option punctuation">!r</span><span class="token punctuation">}</span></span><span class="token string">) -&gt; </span><span class="token interpolation"><span class="token punctuation">{</span>result<span class="token conversion-option punctuation">!r</span><span class="token punctuation">}</span></span><span class="token string">&#39;</span></span><span class="token punctuation">)</span></span>
<span class="line">        <span class="token keyword">return</span> result</span>
<span class="line">    <span class="token keyword">return</span> wrapper</span>
<span class="line"></span>
<span class="line"><span class="token decorator annotation punctuation">@trace</span></span>
<span class="line"><span class="token keyword">def</span> <span class="token function">fibonacci</span><span class="token punctuation">(</span>n<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">if</span> n <span class="token keyword">in</span> <span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">return</span> n</span>
<span class="line">    <span class="token keyword">return</span> fibonacci<span class="token punctuation">(</span>n <span class="token operator">-</span> <span class="token number">2</span><span class="token punctuation">)</span> <span class="token operator">+</span> fibonacci<span class="token punctuation">(</span>n <span class="token operator">-</span> <span class="token number">1</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="闭包" tabindex="-1"><a class="header-anchor" href="#闭包"><span>闭包</span></a></h2><p>内层函数引用了外层作用域的变量,且外层通常返回内层函数。改外层变量要用 <code>nonlocal</code>:</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code><span class="line"><span class="token keyword">def</span> <span class="token function">sort_priority</span><span class="token punctuation">(</span>values<span class="token punctuation">,</span> group<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    found <span class="token operator">=</span> <span class="token boolean">False</span></span>
<span class="line">    <span class="token keyword">def</span> <span class="token function">helper</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">nonlocal</span> found</span>
<span class="line">        <span class="token keyword">if</span> x <span class="token keyword">in</span> group<span class="token punctuation">:</span></span>
<span class="line">            found <span class="token operator">=</span> <span class="token boolean">True</span></span>
<span class="line">            <span class="token keyword">return</span> <span class="token number">0</span><span class="token punctuation">,</span> x</span>
<span class="line">        <span class="token keyword">return</span> <span class="token number">1</span><span class="token punctuation">,</span> x</span>
<span class="line">    values<span class="token punctuation">.</span>sort<span class="token punctuation">(</span>key<span class="token operator">=</span>helper<span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">return</span> found</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>闭包里要改的状态一多,<code>nonlocal</code> 就开始别扭,这时改成一个可调用对象(实现 <code>__call__</code>)更清楚:</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code><span class="line"><span class="token keyword">class</span> <span class="token class-name">Sorter</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">def</span> <span class="token function">__init__</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> group<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">        self<span class="token punctuation">.</span>group <span class="token operator">=</span> group</span>
<span class="line">        self<span class="token punctuation">.</span>found <span class="token operator">=</span> <span class="token boolean">False</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">def</span> <span class="token function">__call__</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> x<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">if</span> x <span class="token keyword">in</span> self<span class="token punctuation">.</span>group<span class="token punctuation">:</span></span>
<span class="line">            self<span class="token punctuation">.</span>found <span class="token operator">=</span> <span class="token boolean">True</span></span>
<span class="line">            <span class="token keyword">return</span> <span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">,</span> x<span class="token punctuation">)</span></span>
<span class="line">        <span class="token keyword">return</span> <span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> x<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">sorter <span class="token operator">=</span> Sorter<span class="token punctuation">(</span>group<span class="token punctuation">)</span></span>
<span class="line">numbers<span class="token punctuation">.</span>sort<span class="token punctuation">(</span>key<span class="token operator">=</span>sorter<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="lambda-的延迟绑定坑" tabindex="-1"><a class="header-anchor" href="#lambda-的延迟绑定坑"><span>lambda 的延迟绑定坑</span></a></h2><p>lambda 捕获的是变量本身而非定义时的值,循环里很容易踩:</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code><span class="line">x <span class="token operator">=</span> <span class="token number">10</span></span>
<span class="line">a <span class="token operator">=</span> <span class="token keyword">lambda</span> y<span class="token punctuation">:</span> x <span class="token operator">+</span> y</span>
<span class="line">x <span class="token operator">=</span> <span class="token number">20</span></span>
<span class="line"><span class="token keyword">print</span><span class="token punctuation">(</span>a<span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 30,用的是最新的 x</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 想在定义时就把值钉住,用默认参数</span></span>
<span class="line">x <span class="token operator">=</span> <span class="token number">10</span></span>
<span class="line">a <span class="token operator">=</span> <span class="token keyword">lambda</span> y<span class="token punctuation">,</span> x<span class="token operator">=</span>x<span class="token punctuation">:</span> x <span class="token operator">+</span> y</span>
<span class="line">x <span class="token operator">=</span> <span class="token number">20</span></span>
<span class="line"><span class="token keyword">print</span><span class="token punctuation">(</span>a<span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 20</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 循环里同理,n=n 把每轮的值固定下来</span></span>
<span class="line">funcs <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token keyword">lambda</span> x<span class="token punctuation">,</span> n<span class="token operator">=</span>n<span class="token punctuation">:</span> x <span class="token operator">+</span> n <span class="token keyword">for</span> n <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span><span class="token number">5</span><span class="token punctuation">)</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token keyword">print</span><span class="token punctuation">(</span><span class="token punctuation">[</span>f<span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">)</span> <span class="token keyword">for</span> f <span class="token keyword">in</span> funcs<span class="token punctuation">]</span><span class="token punctuation">)</span>  <span class="token comment"># [0, 1, 2, 3, 4]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="面向对象的几个内置方法" tabindex="-1"><a class="header-anchor" href="#面向对象的几个内置方法"><span>面向对象的几个内置方法</span></a></h2><ul><li><code>__str__()</code> 把实例转成给人看的字符串;没定义就退回用 <code>__repr__()</code>。</li><li><code>__repr__()</code> 把实例转成字符串,惯例是让 <code>eval(repr(x)) == x</code> 成立。</li><li><code>__format__()</code> 让对象支持 <code>format()</code> 和字符串格式化里的自定义格式码。</li></ul><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code><span class="line">_formats <span class="token operator">=</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token string">&#39;ymd&#39;</span><span class="token punctuation">:</span> <span class="token string">&#39;{d.year}-{d.month}-{d.day}&#39;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&#39;mdy&#39;</span><span class="token punctuation">:</span> <span class="token string">&#39;{d.month}/{d.day}/{d.year}&#39;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&#39;dmy&#39;</span><span class="token punctuation">:</span> <span class="token string">&#39;{d.day}/{d.month}/{d.year}&#39;</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">Date</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">def</span> <span class="token function">__init__</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> year<span class="token punctuation">,</span> month<span class="token punctuation">,</span> day<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">        self<span class="token punctuation">.</span>year<span class="token punctuation">,</span> self<span class="token punctuation">.</span>month<span class="token punctuation">,</span> self<span class="token punctuation">.</span>day <span class="token operator">=</span> year<span class="token punctuation">,</span> month<span class="token punctuation">,</span> day</span>
<span class="line"></span>
<span class="line">    <span class="token keyword">def</span> <span class="token function">__repr__</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">return</span> <span class="token string-interpolation"><span class="token string">f&#39;Date(</span><span class="token interpolation"><span class="token punctuation">{</span>self<span class="token punctuation">.</span>year<span class="token conversion-option punctuation">!r</span><span class="token punctuation">}</span></span><span class="token string">, </span><span class="token interpolation"><span class="token punctuation">{</span>self<span class="token punctuation">.</span>month<span class="token conversion-option punctuation">!r</span><span class="token punctuation">}</span></span><span class="token string">, </span><span class="token interpolation"><span class="token punctuation">{</span>self<span class="token punctuation">.</span>day<span class="token conversion-option punctuation">!r</span><span class="token punctuation">}</span></span><span class="token string">)&#39;</span></span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">def</span> <span class="token function">__str__</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">return</span> <span class="token string-interpolation"><span class="token string">f&#39;(</span><span class="token interpolation"><span class="token punctuation">{</span>self<span class="token punctuation">.</span>year<span class="token punctuation">}</span></span><span class="token string">, </span><span class="token interpolation"><span class="token punctuation">{</span>self<span class="token punctuation">.</span>month<span class="token punctuation">}</span></span><span class="token string">, </span><span class="token interpolation"><span class="token punctuation">{</span>self<span class="token punctuation">.</span>day<span class="token punctuation">}</span></span><span class="token string">)&#39;</span></span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">def</span> <span class="token function">__format__</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> code<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">if</span> code <span class="token operator">==</span> <span class="token string">&#39;&#39;</span><span class="token punctuation">:</span></span>
<span class="line">            code <span class="token operator">=</span> <span class="token string">&#39;ymd&#39;</span></span>
<span class="line">        <span class="token keyword">return</span> _formats<span class="token punctuation">[</span>code<span class="token punctuation">]</span><span class="token punctuation">.</span><span class="token builtin">format</span><span class="token punctuation">(</span>d<span class="token operator">=</span>self<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">d <span class="token operator">=</span> Date<span class="token punctuation">(</span><span class="token number">2020</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">25</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">format</span><span class="token punctuation">(</span>d<span class="token punctuation">)</span><span class="token punctuation">)</span>         <span class="token comment"># 2020-2-25</span></span>
<span class="line"><span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">format</span><span class="token punctuation">(</span>d<span class="token punctuation">,</span> <span class="token string">&#39;mdy&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 2/25/2020</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>@property</code> 把方法当属性用,配 <code>@x.setter</code> 做读写:</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code><span class="line"><span class="token keyword">class</span> <span class="token class-name">Dog</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">def</span> <span class="token function">__init__</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">        self<span class="token punctuation">.</span>_age <span class="token operator">=</span> <span class="token number">0</span></span>
<span class="line">        self<span class="token punctuation">.</span>_name <span class="token operator">=</span> <span class="token boolean">None</span></span>
<span class="line"></span>
<span class="line">    <span class="token decorator annotation punctuation">@property</span></span>
<span class="line">    <span class="token keyword">def</span> <span class="token function">age</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">return</span> self<span class="token punctuation">.</span>_age</span>
<span class="line"></span>
<span class="line">    <span class="token decorator annotation punctuation">@age<span class="token punctuation">.</span>setter</span></span>
<span class="line">    <span class="token keyword">def</span> <span class="token function">age</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> age<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">        self<span class="token punctuation">.</span>_age <span class="token operator">=</span> age</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="常用标准库" tabindex="-1"><a class="header-anchor" href="#常用标准库"><span>常用标准库</span></a></h2><h3 id="collections" tabindex="-1"><a class="header-anchor" href="#collections"><span>collections</span></a></h3><p><code>namedtuple</code> 给元组的字段起名字,<code>_replace</code> 改部分字段:</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code><span class="line"><span class="token keyword">from</span> collections <span class="token keyword">import</span> namedtuple</span>
<span class="line">Stock <span class="token operator">=</span> namedtuple<span class="token punctuation">(</span><span class="token string">&#39;Stock&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token string">&#39;name&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;date&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;price&#39;</span><span class="token punctuation">]</span><span class="token punctuation">)</span></span>
<span class="line">s <span class="token operator">=</span> Stock<span class="token punctuation">(</span><span class="token string">&#39;ACME&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;2012-07-01&#39;</span><span class="token punctuation">,</span> <span class="token number">100</span><span class="token punctuation">)</span></span>
<span class="line">s<span class="token punctuation">.</span>_replace<span class="token punctuation">(</span>price<span class="token operator">=</span><span class="token number">123.45</span><span class="token punctuation">)</span></span>
<span class="line">s<span class="token punctuation">.</span>name  <span class="token comment"># &#39;ACME&#39;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>Counter</code> 统计可哈希元素出现次数,<code>most_common(n)</code> 取前 n 多:</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code><span class="line"><span class="token keyword">from</span> collections <span class="token keyword">import</span> Counter</span>
<span class="line">words <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&#39;look&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;into&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;my&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;eyes&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;look&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;into&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;eyes&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;the&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;eyes&#39;</span><span class="token punctuation">]</span></span>
<span class="line">Counter<span class="token punctuation">(</span>words<span class="token punctuation">)</span><span class="token punctuation">.</span>most_common<span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">)</span>  <span class="token comment"># [(&#39;eyes&#39;, 3), (&#39;look&#39;, 2), (&#39;into&#39;, 2)]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>ChainMap</code> 把多个字典逻辑上拼成一个(并不真合并):重复键取第一个出现的;更新/删除只作用于第一个字典。</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code><span class="line"><span class="token keyword">from</span> collections <span class="token keyword">import</span> ChainMap</span>
<span class="line">a <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token string">&#39;x&#39;</span><span class="token punctuation">:</span> <span class="token number">1</span><span class="token punctuation">,</span> <span class="token string">&#39;z&#39;</span><span class="token punctuation">:</span> <span class="token number">3</span><span class="token punctuation">}</span></span>
<span class="line">b <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token string">&#39;y&#39;</span><span class="token punctuation">:</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token string">&#39;z&#39;</span><span class="token punctuation">:</span> <span class="token number">4</span><span class="token punctuation">}</span></span>
<span class="line">c <span class="token operator">=</span> ChainMap<span class="token punctuation">(</span>a<span class="token punctuation">,</span> b<span class="token punctuation">)</span></span>
<span class="line">c<span class="token punctuation">[</span><span class="token string">&#39;z&#39;</span><span class="token punctuation">]</span>     <span class="token comment"># 3,取第一个字典里的</span></span>
<span class="line"><span class="token keyword">del</span> c<span class="token punctuation">[</span><span class="token string">&#39;x&#39;</span><span class="token punctuation">]</span>  <span class="token comment"># 删的是 a 里的 x</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="operator" tabindex="-1"><a class="header-anchor" href="#operator"><span>operator</span></a></h3><p><code>itemgetter</code> 按字典键取值,常用作排序 key,支持多键:</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code><span class="line"><span class="token keyword">from</span> operator <span class="token keyword">import</span> itemgetter</span>
<span class="line">rows <span class="token operator">=</span> <span class="token punctuation">[</span></span>
<span class="line">    <span class="token punctuation">{</span><span class="token string">&#39;fname&#39;</span><span class="token punctuation">:</span> <span class="token string">&#39;Brian&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;uid&#39;</span><span class="token punctuation">:</span> <span class="token number">1003</span><span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">{</span><span class="token string">&#39;fname&#39;</span><span class="token punctuation">:</span> <span class="token string">&#39;David&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;uid&#39;</span><span class="token punctuation">:</span> <span class="token number">1002</span><span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">]</span></span>
<span class="line"><span class="token builtin">sorted</span><span class="token punctuation">(</span>rows<span class="token punctuation">,</span> key<span class="token operator">=</span>itemgetter<span class="token punctuation">(</span><span class="token string">&#39;uid&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token builtin">sorted</span><span class="token punctuation">(</span>rows<span class="token punctuation">,</span> key<span class="token operator">=</span>itemgetter<span class="token punctuation">(</span><span class="token string">&#39;uid&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;fname&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>attrgetter</code> 同理,取的是对象属性。配 <code>itertools.groupby</code> 按某字段分组(分组前要先按该字段排序):</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code><span class="line"><span class="token keyword">from</span> itertools <span class="token keyword">import</span> groupby</span>
<span class="line">rows<span class="token punctuation">.</span>sort<span class="token punctuation">(</span>key<span class="token operator">=</span>itemgetter<span class="token punctuation">(</span><span class="token string">&#39;date&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">for</span> date<span class="token punctuation">,</span> items <span class="token keyword">in</span> groupby<span class="token punctuation">(</span>rows<span class="token punctuation">,</span> key<span class="token operator">=</span>itemgetter<span class="token punctuation">(</span><span class="token string">&#39;date&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">print</span><span class="token punctuation">(</span>date<span class="token punctuation">,</span> <span class="token builtin">list</span><span class="token punctuation">(</span>items<span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="itertools" tabindex="-1"><a class="header-anchor" href="#itertools"><span>itertools</span></a></h3><p><code>compress</code> 用一个布尔序列当掩码筛选:</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code><span class="line"><span class="token keyword">from</span> itertools <span class="token keyword">import</span> compress</span>
<span class="line">addresses <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&#39;5412 N CLARK&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;5800 E 58TH&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;1060 W ADDISON&#39;</span><span class="token punctuation">]</span></span>
<span class="line">counts <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">,</span> <span class="token number">10</span><span class="token punctuation">,</span> <span class="token number">7</span><span class="token punctuation">]</span></span>
<span class="line">more5 <span class="token operator">=</span> <span class="token punctuation">[</span>n <span class="token operator">&gt;</span> <span class="token number">5</span> <span class="token keyword">for</span> n <span class="token keyword">in</span> counts<span class="token punctuation">]</span></span>
<span class="line"><span class="token builtin">list</span><span class="token punctuation">(</span>compress<span class="token punctuation">(</span>addresses<span class="token punctuation">,</span> more5<span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># [&#39;5800 E 58TH&#39;, &#39;1060 W ADDISON&#39;]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,62)]))}const u=s(t,[["render",o],["__file","python38-features.html.vue"]]),r=JSON.parse('{"path":"/Basic/language/Python/python38-features.html","title":"Python 3.8 新特性与标准库笔记","lang":"en-US","frontmatter":{"date":"2024-11-03T10:13:12.000Z","tag":["Python"]},"git":{"createdTime":1782546817000,"updatedTime":1782546817000,"contributors":[{"name":"BanMing","username":"BanMing","email":"ban-ming@foxmail.com","commits":1,"url":"https://github.com/BanMing"},{"name":"Claude Opus 4.7","username":"Claude Opus 4.7","email":"noreply@anthropic.com","commits":1,"url":"https://github.com/Claude Opus 4.7"}]},"readingTime":{"minutes":4.9,"words":1469},"filePathRelative":"Basic/language/Python/python38-features.md","localizedDate":"November 3, 2024","excerpt":"\\n<p>记 Python 3.8 引入的几个语法,顺带把常用标准库(collections、operator、itertools)和闭包、装饰器、property 这些日常会写到的东西一起整理。</p>\\n<h2>海象表达式 <code>:=</code></h2>\\n<p>可以在表达式内部赋值,省掉一次单独的赋值语句:</p>\\n<div class=\\"language-python line-numbers-mode\\" data-highlighter=\\"prismjs\\" data-ext=\\"py\\"><pre><code><span class=\\"line\\"><span class=\\"token keyword\\">if</span> <span class=\\"token punctuation\\">(</span>a <span class=\\"token operator\\">:=</span> <span class=\\"token number\\">3</span><span class=\\"token punctuation\\">)</span> <span class=\\"token operator\\">&gt;</span> <span class=\\"token number\\">2</span><span class=\\"token punctuation\\">:</span></span>\\n<span class=\\"line\\">    <span class=\\"token keyword\\">print</span><span class=\\"token punctuation\\">(</span>a<span class=\\"token punctuation\\">)</span>  <span class=\\"token comment\\"># 3</span></span>\\n<span class=\\"line\\"></span>\\n<span class=\\"line\\"><span class=\\"token keyword\\">while</span> <span class=\\"token punctuation\\">(</span>a <span class=\\"token operator\\">:=</span> a <span class=\\"token operator\\">+</span> <span class=\\"token number\\">1</span><span class=\\"token punctuation\\">)</span> <span class=\\"token operator\\">&lt;</span> <span class=\\"token number\\">10</span><span class=\\"token punctuation\\">:</span></span>\\n<span class=\\"line\\">    <span class=\\"token keyword\\">print</span><span class=\\"token punctuation\\">(</span>a<span class=\\"token punctuation\\">)</span>  <span class=\\"token comment\\"># 4, 5, 6, 7, 8, 9</span></span>\\n<span class=\\"line\\"></span></code></pre>\\n<div class=\\"line-numbers\\" aria-hidden=\\"true\\" style=\\"counter-reset:line-number 0\\"><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div></div></div>"}');export{u as comp,r as data};
